contracts/BountyMarket.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./DeviceRegistry.sol";
import "./PoACVerifier.sol";

/**
 * @title BountyMarket
 * @author VAPI Project
 * @notice Decentralized bounty marketplace for VAPI autonomous physical
 *         intelligence agents on IoTeX. Enables requesters to post bounties
 *         for real-world data collection, verified through Proof of Autonomous
 *         Cognition (PoAC) records.
 *
 * @dev Lifecycle: Create -> Active -> (Accepted -> Fulfilled | Expired)
 *
 *      Bounty parameters mirror the firmware's `bounty_descriptor_t` from
 *      `economic.h`, with monetary values denominated in native IOTX (wei).
 *
 *      Evidence is linked to verified PoAC records. The contract checks:
 *        - The device accepted this bounty
 *        - The PoAC is verified on-chain (via PoACVerifier)
 *        - Geographic zone containment
 *        - Sensor requirements met
 *        - Sample interval respected
 *
 *      Swarm aggregation enables multiple devices to collaboratively report
 *      on overlapping physical events, producing a confidence-weighted
 *      PhysicalOracleReport suitable for consumption by other DeFi protocols.
 */
contract BountyMarket is Ownable, ReentrancyGuard {

    // -------------------------------------------------------------------------
    //  Constants
    // -------------------------------------------------------------------------

    /// @notice Minimum bounty duration in seconds.
    uint256 public constant MIN_BOUNTY_DURATION = 1 hours;

    /// @notice Maximum bounty duration in seconds.
    uint256 public constant MAX_BOUNTY_DURATION = 365 days;

    /// @notice Coordinate scaling factor: firmware sends lat/lon * 1e7 as int64.
    int64 public constant COORD_SCALE = 1e7;

    /// @notice Platform fee in basis points (e.g., 250 = 2.5%).
    uint16 public platformFeeBps;

    /// @notice Accumulated platform fees available for withdrawal.
    uint256 public accumulatedFees;

    // -------------------------------------------------------------------------
    //  Sensor requirement flags (mirrors firmware BOUNTY_REQUIRES_* defines)
    // -------------------------------------------------------------------------

    uint16 public constant REQUIRES_VOC      = 1 << 0;
    uint16 public constant REQUIRES_TEMP     = 1 << 1;
    uint16 public constant REQUIRES_HUMIDITY = 1 << 2;
    uint16 public constant REQUIRES_PRESSURE = 1 << 3;
    uint16 public constant REQUIRES_MOTION   = 1 << 4;
    uint16 public constant REQUIRES_LIGHT    = 1 << 5;
    uint16 public constant REQUIRES_GPS      = 1 << 6;

    // -------------------------------------------------------------------------
    //  Data structures
    // -------------------------------------------------------------------------

    /// @notice Bounty lifecycle states.
    enum BountyStatus {
        None,       // Default / nonexistent
        Active,     // Open for acceptance and evidence submission
        Fulfilled,  // All requirements met, reward claimed
        Expired     // Deadline passed without fulfillment, refundable
    }

    /**
     * @notice On-chain bounty descriptor.
     * @dev Mirrors `bounty_descriptor_t` from economic.h with EVM-native types.
     *      Coordinates stored as fixed-point int64 (value * 1e7).
     */
    struct BountyDescriptor {
        uint256 bountyId;            // Auto-incremented identifier
        address creator;             // Address that posted the bounty
        uint256 reward;              // Total reward in wei (IOTX)
        uint16  sensorRequirements;  // Bitfield of REQUIRES_* flags
        uint16  minSamples;          // Minimum PoAC submissions required
        uint32  sampleIntervalS;     // Required minimum interval between samples (seconds)
        uint32  durationS;           // Bounty duration from creation
        uint64  deadlineMs;          // Absolute deadline (Unix ms)
        int64   zoneLatMin;          // Geographic bounding box (lat * 1e7)
        int64   zoneLatMax;
        int64   zoneLonMin;
        int64   zoneLonMax;
        int256  vocThreshold;        // VOC threshold (scaled fixed-point, 0 = unused)
        int256  tempThresholdHi;     // High temperature threshold (scaled, 0 = unused)
        int256  tempThresholdLo;     // Low temperature threshold (scaled, 0 = unused)
        BountyStatus status;
        uint256 createdAt;           // Block timestamp of creation
    }

    /**
     * @notice Per-device acceptance record for a bounty.
     */
    struct Acceptance {
        bool    accepted;           // Whether the device accepted this bounty
        uint64  acceptedAt;         // Timestamp of acceptance
        uint16  samplesSubmitted;   // Count of valid evidence submissions
        int64   lastSampleTimestampMs; // Timestamp of last submitted sample
    }

    /**
     * @notice Evidence linking a PoAC record to a bounty.
     */
    struct Evidence {
        bytes32 deviceId;
        bytes32 recordHash;
        int64   timestampMs;
        int64   latitude;
        int64   longitude;
    }

    /**
     * @notice Swarm aggregation report — physical oracle output.
     */
    struct SwarmReport {
        uint256 bountyId;
        uint256 deviceCount;         // Number of distinct devices
        uint256 totalSamples;        // Total PoAC records aggregated
        uint16  confidenceScore;     // Weighted confidence [0, 10000] (basis points)
        uint8   consensusInference;  // Most common inference result across devices
        int64   medianLatitude;      // Median location (approx)
        int64   medianLongitude;
        int64   earliestTimestampMs;
        int64   latestTimestampMs;
    }

    // -------------------------------------------------------------------------
    //  State
    // -------------------------------------------------------------------------

    /// @notice References to companion contracts.
    PoACVerifier public poACVerifier;
    DeviceRegistry public deviceRegistry;

    /// @notice Auto-incrementing bounty ID counter.
    uint256 public nextBountyId;

    /// @notice bountyId => BountyDescriptor.
    mapping(uint256 => BountyDescriptor) public bounties;

    /// @notice bountyId => deviceId => Acceptance.
    mapping(uint256 => mapping(bytes32 => Acceptance)) public acceptances;

    /// @notice bountyId => array of Evidence records.
    mapping(uint256 => Evidence[]) private _evidence;

    /// @notice bountyId => set of deviceIds that have accepted.
    mapping(uint256 => bytes32[]) private _acceptedDevices;

    /// @notice recordHash => bountyId (prevent double-submission of evidence).
    mapping(bytes32 => uint256) public evidenceRecordToBounty;

    // -------------------------------------------------------------------------
    //  Events
    // -------------------------------------------------------------------------

    /// @notice Emitted when a new bounty is posted.
    event BountyPosted(
        uint256 indexed bountyId,
        address indexed creator,
        uint256 reward,
        uint16  sensorRequirements,
        uint16  minSamples,
        uint64  deadlineMs
    );

    /// @notice Emitted when a device accepts a bounty.
    event BountyAccepted(
        uint256 indexed bountyId,
        bytes32 indexed deviceId,
        uint64  acceptedAt
    );

    /// @notice Emitted when evidence is submitted linking a PoAC to a bounty.
    event EvidenceSubmitted(
        uint256 indexed bountyId,
        bytes32 indexed deviceId,
        bytes32 indexed recordHash,
        uint16  sampleNumber
    );

    /// @notice Emitted when a device claims the reward for a fulfilled bounty.
    event RewardClaimed(
        uint256 indexed bountyId,
        bytes32 indexed deviceId,
        address indexed recipient,
        uint256 amount
    );

    /// @notice Emitted when a bounty expires and the creator is refunded.
    event BountyExpired(
        uint256 indexed bountyId,
        address indexed creator,
        uint256 refundAmount
    );

    /**
     * @notice Emitted when a swarm aggregation produces a physical oracle report.
     * @dev This event is designed to be consumed by other on-chain protocols
     *      as a verified physical-world data feed.
     */
    event PhysicalOracleReport(
        uint256 indexed bountyId,
        uint256 deviceCount,
        uint256 totalSamples,
        uint16  confidenceScore,
        uint8   consensusInference,
        int64   medianLatitude,
        int64   medianLongitude,
        int64   earliestTimestampMs,
        int64   latestTimestampMs
    );

    // -------------------------------------------------------------------------
    //  Errors
    // -------------------------------------------------------------------------

    error BountyNotFound(uint256 bountyId);
    error BountyNotActive(uint256 bountyId);
    error BountyAlreadyFulfilled(uint256 bountyId);
    error BountyNotExpired(uint256 bountyId);
    error InsufficientReward();
    error InvalidDuration(uint256 duration);
    error InvalidZone();
    error InvalidMinSamples();
    error DeviceNotRegistered(bytes32 deviceId);
    error DeviceNotActive(bytes32 deviceId);
    error AlreadyAccepted(uint256 bountyId, bytes32 deviceId);
    error NotAccepted(uint256 bountyId, bytes32 deviceId);
    error RecordNotVerified(bytes32 recordHash);
    error RecordAlreadyUsed(bytes32 recordHash, uint256 existingBountyId);
    error OutsideGeographicZone(int64 lat, int64 lon);
    error SampleIntervalNotRespected(int64 lastTs, int64 currentTs, uint32 requiredInterval);
    error MinSamplesNotReached(uint256 bountyId, uint16 submitted, uint16 required);
    error NotBountyCreator(uint256 bountyId, address caller);
    error NoDevicesForAggregation(uint256 bountyId);
    error TransferFailed();
    /// @notice Thrown when a device's registration tier does not permit bounty claims.
    error IneligibleTier(bytes32 deviceId);

    // -------------------------------------------------------------------------
    //  Constructor
    // -------------------------------------------------------------------------

    /**
     * @param _poACVerifier   Address of deployed PoACVerifier contract.
     * @param _deviceRegistry Address of deployed DeviceRegistry contract.
     * @param _platformFeeBps Platform fee in basis points (e.g., 250 for 2.5%).
     */
    constructor(
        address _poACVerifier,
        address _deviceRegistry,
        uint16  _platformFeeBps
    )
        Ownable(msg.sender)
    {
        poACVerifier = PoACVerifier(_poACVerifier);
        deviceRegistry = DeviceRegistry(_deviceRegistry);
        platformFeeBps = _platformFeeBps;
        nextBountyId = 1; // Start at 1; 0 is POAC_NO_BOUNTY sentinel
    }

    // -------------------------------------------------------------------------
    //  Admin
    // -------------------------------------------------------------------------

    /**
     * @notice Update the platform fee. Owner-only.
     * @param _newFeeBps New fee in basis points (max 1000 = 10%).
     */
    function setPlatformFee(uint16 _newFeeBps) external onlyOwner {
        require(_newFeeBps <= 1000, "BountyMarket: fee cannot exceed 10%");
        platformFeeBps = _newFeeBps;
    }

    /**
     * @notice Withdraw accumulated platform fees. Owner-only.
     */
    function withdrawFees() external onlyOwner nonReentrant {
        uint256 amount = accumulatedFees;
        accumulatedFees = 0;
        (bool success, ) = payable(owner()).call{value: amount}("");
        if (!success) revert TransferFailed();
    }

    // -------------------------------------------------------------------------
    //  Bounty creation
    // -------------------------------------------------------------------------

    /**
     * @notice Post a new bounty for physical data collection.
     *
     * @dev The caller deposits the full reward amount in IOTX (msg.value).
     *      The bounty becomes Active immediately and remains so until the
     *      deadline or until fulfilled.
     *
     *      Parameters mirror `bounty_descriptor_t` from `economic.h`:
     *        - sensorRequirements: bitfield of REQUIRES_* flags
     *        - minSamples: minimum PoAC submissions needed for fulfillment
     *        - sampleIntervalS: minimum seconds between consecutive samples
     *        - durationS: bounty duration from creation (determines deadline)
     *        - zone coordinates: bounding box in fixed-point (lat/lon * 1e7)
     *        - thresholds: sensor-specific triggers (0 = no threshold)
     *
     * @param _sensorRequirements Bitfield of required sensor capabilities.
     * @param _minSamples         Minimum number of valid PoAC evidence samples.
     * @param _sampleIntervalS    Minimum interval between samples in seconds.
     * @param _durationS          Bounty duration in seconds.
     * @param _zoneLatMin         Zone bounding box south (latitude * 1e7).
     * @param _zoneLatMax         Zone bounding box north (latitude * 1e7).
     * @param _zoneLonMin         Zone bounding box west (longitude * 1e7).
     * @param _zoneLonMax         Zone bounding box east (longitude * 1e7).
     * @param _vocThreshold       VOC resistance threshold (0 = unused).
     * @param _tempThresholdHi    High temperature threshold (0 = unused).
     * @param _tempThresholdLo    Low temperature threshold (0 = unused).
     *
     * @return bountyId The ID of the newly created bounty.
     */
    function postBounty(
        uint16  _sensorRequirements,
        uint16  _minSamples,
        uint32  _sampleIntervalS,
        uint32  _durationS,
        int64   _zoneLatMin,
        int64   _zoneLatMax,
        int64   _zoneLonMin,
        int64   _zoneLonMax,
        int256  _vocThreshold,
        int256  _tempThresholdHi,
        int256  _tempThresholdLo
    )
        external
        payable
        nonReentrant
        returns (uint256 bountyId)
    {
        // Validate reward
        if (msg.value == 0) revert InsufficientReward();

        // Validate duration
        if (_durationS < MIN_BOUNTY_DURATION || _durationS > MAX_BOUNTY_DURATION) {
            revert InvalidDuration(_durationS);
        }

        // Validate geographic zone (min < max)
        if (_zoneLatMin >= _zoneLatMax || _zoneLonMin >= _zoneLonMax) {
            revert InvalidZone();
        }

        // Validate min samples
        if (_minSamples == 0) revert InvalidMinSamples();

        // Assign ID
        bountyId = nextBountyId++;

        // Compute deadline
        uint64 deadlineMs = uint64((block.timestamp + uint256(_durationS)) * 1000);

        // Store bounty
        BountyDescriptor storage b = bounties[bountyId];
        b.bountyId = bountyId;
        b.creator = msg.sender;
        b.reward = msg.value;
        b.sensorRequirements = _sensorRequirements;
        b.minSamples = _minSamples;
        b.sampleIntervalS = _sampleIntervalS;
        b.durationS = _durationS;
        b.deadlineMs = deadlineMs;
        b.zoneLatMin = _zoneLatMin;
        b.zoneLatMax = _zoneLatMax;
        b.zoneLonMin = _zoneLonMin;
        b.zoneLonMax = _zoneLonMax;
        b.vocThreshold = _vocThreshold;
        b.tempThresholdHi = _tempThresholdHi;
        b.tempThresholdLo = _tempThresholdLo;
        b.status = BountyStatus.Active;
        b.createdAt = block.timestamp;

        emit BountyPosted(
            bountyId,
            msg.sender,
            msg.value,
            _sensorRequirements,
            _minSamples,
            deadlineMs
        );
    }

    // -------------------------------------------------------------------------
    //  Bounty acceptance
    // -------------------------------------------------------------------------

    /**
     * @notice Signal that a device intends to fulfill a bounty.
     *
     * @dev The device must be registered and active in DeviceRegistry.
     *      A device can only accept a bounty once. Acceptance is recorded
     *      on-chain so the firmware can track committed bounties.
     *
     * @param _bountyId  The bounty to accept.
     * @param _deviceId  The device accepting the bounty.
     */
    function acceptBounty(uint256 _bountyId, bytes32 _deviceId) external {
        BountyDescriptor storage b = bounties[_bountyId];
        if (b.status == BountyStatus.None) revert BountyNotFound(_bountyId);
        if (b.status != BountyStatus.Active) revert BountyNotActive(_bountyId);

        // Check deadline hasn't passed
        if (block.timestamp * 1000 > uint256(b.deadlineMs)) {
            revert BountyNotActive(_bountyId);
        }

        // Verify device is registered and active
        if (!deviceRegistry.isDeviceActive(_deviceId)) {
            revert DeviceNotActive(_deviceId);
        }

        // Check not already accepted
        if (acceptances[_bountyId][_deviceId].accepted) {
            revert AlreadyAccepted(_bountyId, _deviceId);
        }

        // Record acceptance
        acceptances[_bountyId][_deviceId] = Acceptance({
            accepted: true,
            acceptedAt: uint64(block.timestamp),
            samplesSubmitted: 0,
            lastSampleTimestampMs: 0
        });

        _acceptedDevices[_bountyId].push(_deviceId);

        emit BountyAccepted(_bountyId, _deviceId, uint64(block.timestamp));
    }

    // -------------------------------------------------------------------------
    //  Evidence submission
    // -------------------------------------------------------------------------

    /**
     * @notice Submit a verified PoAC record as evidence for a bounty.
     *
     * @dev Checks performed:
     *      1. Bounty is active and not past deadline.
     *      2. Device accepted this bounty.
     *      3. PoAC record is verified on-chain (via PoACVerifier).
     *      4. Record is not already used as evidence for another bounty.
     *      5. PoAC latitude/longitude is within the bounty's geographic zone.
     *      6. Sample interval is respected (time since last submission).
     *
     * @param _bountyId    The bounty this evidence fulfills.
     * @param _deviceId    The device submitting evidence.
     * @param _recordHash  The hash of the verified PoAC record.
     * @param _latitude    Record latitude (fixed-point * 1e7), must match PoAC.
     * @param _longitude   Record longitude (fixed-point * 1e7), must match PoAC.
     * @param _timestampMs Record timestamp in milliseconds, must match PoAC.
     */
    function submitEvidence(
        uint256 _bountyId,
        bytes32 _deviceId,
        bytes32 _recordHash,
        int64   _latitude,
        int64   _longitude,
        int64   _timestampMs
    )
        external
        nonReentrant
    {
        BountyDescriptor storage b = bounties[_bountyId];
        if (b.status == BountyStatus.None) revert BountyNotFound(_bountyId);
        if (b.status != BountyStatus.Active) revert BountyNotActive(_bountyId);

        // Check deadline
        if (uint256(uint64(_timestampMs)) > uint256(b.deadlineMs)) {
            revert BountyNotActive(_bountyId);
        }

        // Check device accepted this bounty
        Acceptance storage acc = acceptances[_bountyId][_deviceId];
        if (!acc.accepted) revert NotAccepted(_bountyId, _deviceId);

        // Check device tier allows bounty claims (Emulated tier is blocked)
        if (!deviceRegistry.canClaimBounty(_deviceId)) revert IneligibleTier(_deviceId);

        // Check PoAC is verified on-chain
        if (!poACVerifier.isRecordVerified(_recordHash)) {
            revert RecordNotVerified(_recordHash);
        }

        // Check record not already used as evidence
        if (evidenceRecordToBounty[_recordHash] != 0) {
            revert RecordAlreadyUsed(_recordHash, evidenceRecordToBounty[_recordHash]);
        }

        // Check geographic zone containment
        if (
            _latitude < b.zoneLatMin || _latitude > b.zoneLatMax ||
            _longitude < b.zoneLonMin || _longitude > b.zoneLonMax
        ) {
            revert OutsideGeographicZone(_latitude, _longitude);
        }

        // Check sample interval
        if (acc.samplesSubmitted > 0 && b.sampleIntervalS > 0) {
            int64 requiredGapMs = int64(uint64(b.sampleIntervalS)) * 1000;
            if (_timestampMs - acc.lastSampleTimestampMs < requiredGapMs) {
                revert SampleIntervalNotRespected(
                    acc.lastSampleTimestampMs,
                    _timestampMs,
                    b.sampleIntervalS
                );
            }
        }

        // Record evidence
        _evidence[_bountyId].push(Evidence({
            deviceId: _deviceId,
            recordHash: _recordHash,
            timestampMs: _timestampMs,
            latitude: _latitude,
            longitude: _longitude
        }));

        evidenceRecordToBounty[_recordHash] = _bountyId;
        acc.samplesSubmitted++;
        acc.lastSampleTimestampMs = _timestampMs;

        emit EvidenceSubmitted(
            _bountyId,
            _deviceId,
            _recordHash,
            acc.samplesSubmitted
        );
    }

    // -------------------------------------------------------------------------
    //  Reward claim
    // -------------------------------------------------------------------------

    /**
     * @notice Claim the bounty reward after fulfillment requirements are met.
     *
     * @dev Requires that the device has submitted at least minSamples valid
     *      evidence records. The reward is transferred to the device owner
     *      address (from DeviceRegistry). A platform fee is deducted.
     *
     *      Any device that has met the minimum samples can claim. In a
     *      multi-device scenario, the first claimer receives the reward.
     *
     * @param _bountyId  The bounty to claim.
     * @param _deviceId  The device claiming the reward.
     */
    function claimReward(uint256 _bountyId, bytes32 _deviceId)
        external
        nonReentrant
    {
        BountyDescriptor storage b = bounties[_bountyId];
        if (b.status == BountyStatus.None) revert BountyNotFound(_bountyId);
        if (b.status == BountyStatus.Fulfilled) revert BountyAlreadyFulfilled(_bountyId);
        if (b.status != BountyStatus.Active) revert BountyNotActive(_bountyId);

        // Check device accepted and submitted enough samples
        Acceptance storage acc = acceptances[_bountyId][_deviceId];
        if (!acc.accepted) revert NotAccepted(_bountyId, _deviceId);
        if (acc.samplesSubmitted < b.minSamples) {
            revert MinSamplesNotReached(_bountyId, acc.samplesSubmitted, b.minSamples);
        }

        // Mark bounty as fulfilled
        b.status = BountyStatus.Fulfilled;

        // Compute fee and payout
        uint256 fee = (b.reward * uint256(platformFeeBps)) / 10000;
        uint256 payout = b.reward - fee;
        accumulatedFees += fee;

        // Get device owner from registry
        DeviceRegistry.DeviceInfo memory devInfo = deviceRegistry.getDeviceInfo(_deviceId);
        address recipient = devInfo.owner;

        // Transfer reward to device owner
        (bool success, ) = payable(recipient).call{value: payout}("");
        if (!success) revert TransferFailed();

        // Update device reputation (corroboration bonus for completing a bounty)
        try deviceRegistry.updateReputation(_deviceId, 0, 1, 0) {} catch {}

        emit RewardClaimed(_bountyId, _deviceId, recipient, payout);
    }

    // -------------------------------------------------------------------------
    //  Bounty expiration
    // -------------------------------------------------------------------------

    /**
     * @notice Expire an unfulfilled bounty and refund the creator.
     *
     * @dev Can be called by anyone after the deadline has passed, but only
     *      if the bounty is still Active (not Fulfilled).
     *
     * @param _bountyId The bounty to expire.
     */
    function expireBounty(uint256 _bountyId) external nonReentrant {
        BountyDescriptor storage b = bounties[_bountyId];
        if (b.status == BountyStatus.None) revert BountyNotFound(_bountyId);
        if (b.status != BountyStatus.Active) revert BountyNotActive(_bountyId);

        // Check deadline has passed
        if (block.timestamp * 1000 <= uint256(b.deadlineMs)) {
            revert BountyNotExpired(_bountyId);
        }

        // Mark as expired
        b.status = BountyStatus.Expired;

        // Refund full reward to creator
        uint256 refund = b.reward;
        (bool success, ) = payable(b.creator).call{value: refund}("");
        if (!success) revert TransferFailed();

        emit BountyExpired(_bountyId, b.creator, refund);
    }

    // -------------------------------------------------------------------------
    //  Swarm aggregation
    // -------------------------------------------------------------------------

    /**
     * @notice Aggregate evidence from multiple devices into a swarm report.
     *
     * @dev Takes arrays of PoAC record hashes from different devices that
     *      observed overlapping events within a bounty's zone and time window.
     *      Computes a confidence score based on:
     *        - Number of independent devices (more devices = higher confidence)
     *        - Average device reputation scores
     *        - Consensus on inference result
     *
     *      Emits a {PhysicalOracleReport} event that serves as a verified
     *      physical-world data feed for other on-chain consumers.
     *
     * @param _bountyId     The bounty context for aggregation.
     * @param _deviceIds    Array of contributing device IDs.
     * @param _recordHashes Array of verified PoAC record hashes.
     * @param _latitudes    Array of record latitudes (fixed-point * 1e7).
     * @param _longitudes   Array of record longitudes (fixed-point * 1e7).
     * @param _timestampsMs Array of record timestamps (Unix ms).
     * @param _inferences   Array of inference result codes from each record.
     *
     * @return report The computed SwarmReport.
     */
    function aggregateSwarmReport(
        uint256   _bountyId,
        bytes32[] calldata _deviceIds,
        bytes32[] calldata _recordHashes,
        int64[]   calldata _latitudes,
        int64[]   calldata _longitudes,
        int64[]   calldata _timestampsMs,
        uint8[]   calldata _inferences
    )
        external
        returns (SwarmReport memory report)
    {
        uint256 count = _deviceIds.length;
        require(
            count == _recordHashes.length &&
            count == _latitudes.length &&
            count == _longitudes.length &&
            count == _timestampsMs.length &&
            count == _inferences.length,
            "BountyMarket: array length mismatch"
        );
        if (count == 0) revert NoDevicesForAggregation(_bountyId);

        BountyDescriptor storage b = bounties[_bountyId];
        if (b.status == BountyStatus.None) revert BountyNotFound(_bountyId);

        // Validate all records are verified and count unique devices
        uint256 totalReputation = 0;
        uint256 uniqueDevices = 0;
        int64 earliestTs = type(int64).max;
        int64 latestTs = type(int64).min;
        int64 latSum = 0;
        int64 lonSum = 0;

        // Inference consensus: count occurrences of each inference result
        // Use a simple approach for up to 256 possible values
        uint256[256] memory inferenceCounts;

        // Track unique device IDs (simple O(n^2) check, acceptable for small swarms)
        bytes32[] memory seenDevices = new bytes32[](count);

        for (uint256 i = 0; i < count; i++) {
            // Verify each record is on-chain verified
            require(
                poACVerifier.isRecordVerified(_recordHashes[i]),
                "BountyMarket: unverified record in swarm"
            );

            // Check geographic zone
            require(
                _latitudes[i] >= b.zoneLatMin && _latitudes[i] <= b.zoneLatMax &&
                _longitudes[i] >= b.zoneLonMin && _longitudes[i] <= b.zoneLonMax,
                "BountyMarket: record outside zone"
            );

            // Track unique devices
            bool isNew = true;
            for (uint256 j = 0; j < uniqueDevices; j++) {
                if (seenDevices[j] == _deviceIds[i]) {
                    isNew = false;
                    break;
                }
            }
            if (isNew) {
                seenDevices[uniqueDevices] = _deviceIds[i];
                uniqueDevices++;

                // Accumulate reputation of unique devices
                try deviceRegistry.getReputationScore(_deviceIds[i]) returns (uint16 rep) {
                    totalReputation += uint256(rep);
                } catch {}

                // Update corroboration count for this device
                try deviceRegistry.updateReputation(_deviceIds[i], 0, 1, 0) {} catch {}
            }

            // Track timestamps
            if (_timestampsMs[i] < earliestTs) earliestTs = _timestampsMs[i];
            if (_timestampsMs[i] > latestTs) latestTs = _timestampsMs[i];

            // Accumulate location (for approximate median via mean)
            latSum += _latitudes[i];
            lonSum += _longitudes[i];

            // Count inference results
            inferenceCounts[_inferences[i]]++;
        }

        // Compute consensus inference (mode)
        uint8 consensusInference = 0;
        uint256 maxCount = 0;
        for (uint256 k = 0; k < 256; k++) {
            if (inferenceCounts[k] > maxCount) {
                maxCount = inferenceCounts[k];
                consensusInference = uint8(k);
            }
        }

        // Compute confidence score:
        //   deviceFactor = min(uniqueDevices, 10) * 1000 (up to 10000 for 10+ devices)
        //   reputationFactor = avgReputation (already in basis points, max 10000)
        //   consensusFactor = (consensusCount / totalRecords) * 10000
        //   confidenceScore = (deviceFactor + reputationFactor + consensusFactor) / 3
        uint256 deviceFactor = (uniqueDevices > 10 ? 10 : uniqueDevices) * 1000;
        uint256 avgReputation = uniqueDevices > 0 ? totalReputation / uniqueDevices : 0;
        uint256 consensusFactor = (maxCount * 10000) / count;
        uint256 rawConfidence = (deviceFactor + avgReputation + consensusFactor) / 3;
        uint16 confidenceScore = rawConfidence > 10000
            ? uint16(10000)
            : uint16(rawConfidence);

        // Compute approximate median location (using mean as approximation)
        int64 medianLat = int64(latSum / int64(int256(count)));
        int64 medianLon = int64(lonSum / int64(int256(count)));

        // Build report
        report = SwarmReport({
            bountyId: _bountyId,
            deviceCount: uniqueDevices,
            totalSamples: count,
            confidenceScore: confidenceScore,
            consensusInference: consensusInference,
            medianLatitude: medianLat,
            medianLongitude: medianLon,
            earliestTimestampMs: earliestTs,
            latestTimestampMs: latestTs
        });

        emit PhysicalOracleReport(
            _bountyId,
            uniqueDevices,
            count,
            confidenceScore,
            consensusInference,
            medianLat,
            medianLon,
            earliestTs,
            latestTs
        );
    }

    // -------------------------------------------------------------------------
    //  View functions
    // -------------------------------------------------------------------------

    /**
     * @notice Get the full bounty descriptor.
     * @param _bountyId Bounty identifier.
     * @return The BountyDescriptor struct.
     */
    function getBounty(uint256 _bountyId)
        external
        view
        returns (BountyDescriptor memory)
    {
        BountyDescriptor storage b = bounties[_bountyId];
        if (b.status == BountyStatus.None) revert BountyNotFound(_bountyId);
        return b;
    }

    /**
     * @notice Get the acceptance status for a device on a bounty.
     * @param _bountyId Bounty identifier.
     * @param _deviceId Device identifier.
     * @return The Acceptance struct.
     */
    function getAcceptance(uint256 _bountyId, bytes32 _deviceId)
        external
        view
        returns (Acceptance memory)
    {
        return acceptances[_bountyId][_deviceId];
    }

    /**
     * @notice Get the count of evidence records submitted for a bounty.
     * @param _bountyId Bounty identifier.
     * @return count Number of evidence submissions.
     */
    function getEvidenceCount(uint256 _bountyId)
        external
        view
        returns (uint256 count)
    {
        return _evidence[_bountyId].length;
    }

    /**
     * @notice Get a specific evidence record by index.
     * @param _bountyId Bounty identifier.
     * @param _index    Index into the evidence array.
     * @return The Evidence struct.
     */
    function getEvidence(uint256 _bountyId, uint256 _index)
        external
        view
        returns (Evidence memory)
    {
        return _evidence[_bountyId][_index];
    }

    /**
     * @notice Get the list of device IDs that accepted a bounty.
     * @param _bountyId Bounty identifier.
     * @return Array of device IDs.
     */
    function getAcceptedDevices(uint256 _bountyId)
        external
        view
        returns (bytes32[] memory)
    {
        return _acceptedDevices[_bountyId];
    }
}

contracts/DeviceRegistry.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title DeviceRegistry
 * @author VAPI Project
 * @notice Manages registration and reputation of VAPI autonomous devices on IoTeX.
 *
 * @dev Each device is identified by a `deviceId` derived as keccak256 of its
 *      uncompressed SEC1 P256 public key (65 bytes: 0x04 || x || y).
 *
 *      IoTeX supports ECDSA-P256 signature verification via a precompile at
 *      address 0x0100. The EVM does not natively support P256, so all on-chain
 *      signature checks MUST use this precompile. See {PoACVerifier} for usage.
 *
 *      Registration requires a deposit to prevent Sybil attacks. The deposit is
 *      held for the lifetime of the device registration and can be reclaimed
 *      upon deactivation after a cooldown period.
 *
 *      Integrates with IoTeX ioID: the deviceId concept maps to the ioID
 *      decentralized identity, enabling cross-protocol device lookup.
 */
contract DeviceRegistry is Ownable, ReentrancyGuard {

    // -------------------------------------------------------------------------
    //  Constants
    // -------------------------------------------------------------------------

    /// @notice Length of an uncompressed SEC1 P256 public key (0x04 || x || y).
    uint256 public constant PUBKEY_LENGTH = 65;

    /// @notice Minimum registration deposit in wei (anti-Sybil).
    uint256 public minimumDeposit;

    /// @notice Cooldown period after deactivation before deposit can be withdrawn.
    uint256 public constant DEACTIVATION_COOLDOWN = 7 days;

    /// @notice Maximum value for the reputation score (basis-point scale, 10000 = 100%).
    uint16 public constant MAX_REPUTATION = 10000;

    // -------------------------------------------------------------------------
    //  Data structures
    // -------------------------------------------------------------------------

    /**
     * @notice On-chain metadata for a registered VAPI device.
     * @param owner              The Ethereum address that registered this device.
     * @param registeredAt       Block timestamp of registration.
     * @param deactivatedAt      Block timestamp of deactivation (0 if active).
     * @param deposit            Amount of IOTX deposited at registration.
     * @param active             Whether the device is currently active.
     * @param pubkey             Uncompressed SEC1 P256 public key (65 bytes).
     * @param verifiedPoACCount  Total number of PoAC records verified on-chain for this device.
     * @param corroborationCount Number of times this device's reports were corroborated by swarm.
     * @param disputeCount       Number of disputes raised against this device.
     * @param reputationScore    Computed reputation score [0, MAX_REPUTATION].
     */
    struct DeviceInfo {
        address owner;
        uint64  registeredAt;
        uint64  deactivatedAt;
        uint256 deposit;
        bool    active;
        bytes   pubkey;
        uint32  verifiedPoACCount;
        uint32  corroborationCount;
        uint32  disputeCount;
        uint16  reputationScore;
    }

    // -------------------------------------------------------------------------
    //  State
    // -------------------------------------------------------------------------

    /// @notice deviceId => DeviceInfo. deviceId = keccak256(pubkey).
    mapping(bytes32 => DeviceInfo) private _devices;

    /// @notice Addresses authorized to call updateReputation (e.g. PoACVerifier, BountyMarket).
    mapping(address => bool) public reputationUpdaters;

    /// @notice Total number of registered devices (including deactivated).
    uint256 public deviceCount;

    // -------------------------------------------------------------------------
    //  Events
    // -------------------------------------------------------------------------

    /// @notice Emitted when a new device is registered.
    event DeviceRegistered(
        bytes32 indexed deviceId,
        address indexed owner,
        uint256 deposit,
        uint64  registeredAt
    );

    /// @notice Emitted when a device is deactivated by its owner.
    event DeviceDeactivated(
        bytes32 indexed deviceId,
        address indexed owner,
        uint64  deactivatedAt
    );

    /// @notice Emitted when a device's reputation score is updated.
    event ReputationUpdated(
        bytes32 indexed deviceId,
        uint16  oldScore,
        uint16  newScore,
        uint32  verifiedPoACCount,
        uint32  corroborationCount,
        uint32  disputeCount
    );

    /// @notice Emitted when deposit is withdrawn after deactivation + cooldown.
    event DepositWithdrawn(
        bytes32 indexed deviceId,
        address indexed owner,
        uint256 amount
    );

    // -------------------------------------------------------------------------
    //  Errors
    // -------------------------------------------------------------------------

    error InvalidPubkeyLength(uint256 provided, uint256 expected);
    error InvalidPubkeyPrefix(uint8 provided);
    error DeviceAlreadyRegistered(bytes32 deviceId);
    error InsufficientDeposit(uint256 provided, uint256 required);
    error DeviceNotFound(bytes32 deviceId);
    error DeviceNotActive(bytes32 deviceId);
    error NotDeviceOwner(bytes32 deviceId, address caller);
    error CooldownNotElapsed(bytes32 deviceId, uint256 availableAt);
    error DepositAlreadyWithdrawn(bytes32 deviceId);
    error NotAuthorizedUpdater(address caller);

    // -------------------------------------------------------------------------
    //  Modifiers
    // -------------------------------------------------------------------------

    /// @dev Restricts access to authorized reputation updaters or the contract owner.
    modifier onlyReputationUpdater() {
        if (!reputationUpdaters[msg.sender] && msg.sender != owner()) {
            revert NotAuthorizedUpdater(msg.sender);
        }
        _;
    }

    // -------------------------------------------------------------------------
    //  Constructor
    // -------------------------------------------------------------------------

    /**
     * @param _minimumDeposit Initial minimum deposit in wei for device registration.
     */
    constructor(uint256 _minimumDeposit) Ownable(msg.sender) {
        minimumDeposit = _minimumDeposit;
    }

    // -------------------------------------------------------------------------
    //  Admin functions
    // -------------------------------------------------------------------------

    /**
     * @notice Update the minimum registration deposit. Owner-only.
     * @param _newMinimum New minimum deposit in wei.
     */
    function setMinimumDeposit(uint256 _newMinimum) external onlyOwner {
        minimumDeposit = _newMinimum;
    }

    /**
     * @notice Grant or revoke reputation-updater role (for PoACVerifier, BountyMarket).
     * @param _updater Address to grant/revoke.
     * @param _authorized True to grant, false to revoke.
     */
    function setReputationUpdater(address _updater, bool _authorized) external onlyOwner {
        reputationUpdaters[_updater] = _authorized;
    }

    // -------------------------------------------------------------------------
    //  Registration
    // -------------------------------------------------------------------------

    /**
     * @notice Register a new VAPI device with its P256 public key.
     *
     * @dev The caller becomes the device owner. A deposit >= minimumDeposit must
     *      be sent with the transaction. The deviceId is derived as
     *      keccak256(pubkey) and must not already be registered.
     *
     *      The pubkey must be a 65-byte uncompressed SEC1 point (prefix 0x04).
     *      Actual P256 curve-point validation is deferred to the first PoAC
     *      verification via the IoTeX P256 precompile (0x0100).
     *
     * @param _pubkey Uncompressed SEC1 P256 public key (65 bytes).
     * @return deviceId The derived device identifier.
     */
    function registerDevice(bytes calldata _pubkey)
        external
        payable
        virtual
        nonReentrant
        returns (bytes32 deviceId)
    {
        return _registerCore(_pubkey, minimumDeposit);
    }

    /// @dev Called by registerDevice and TieredDeviceRegistry._registerTiered.
    ///      Separated to allow tier-specific deposit validation by the child
    ///      without triggering a double nonReentrant guard via super call.
    function _registerCore(bytes calldata _pubkey, uint256 _requiredDeposit)
        internal returns (bytes32 deviceId)
    {
        // Validate pubkey format
        if (_pubkey.length != PUBKEY_LENGTH) {
            revert InvalidPubkeyLength(_pubkey.length, PUBKEY_LENGTH);
        }
        if (uint8(_pubkey[0]) != 0x04) {
            revert InvalidPubkeyPrefix(uint8(_pubkey[0]));
        }

        // Derive device identity
        deviceId = keccak256(_pubkey);

        // Ensure not already registered
        if (_devices[deviceId].registeredAt != 0) {
            revert DeviceAlreadyRegistered(deviceId);
        }

        // Enforce deposit
        if (msg.value < _requiredDeposit) {
            revert InsufficientDeposit(msg.value, _requiredDeposit);
        }

        // Store device info
        DeviceInfo storage dev = _devices[deviceId];
        dev.owner          = msg.sender;
        dev.registeredAt   = uint64(block.timestamp);
        dev.deposit        = msg.value;
        dev.active         = true;
        dev.pubkey         = _pubkey;
        dev.reputationScore = 5000; // Start at 50% — neutral reputation

        deviceCount++;

        emit DeviceRegistered(deviceId, msg.sender, msg.value, uint64(block.timestamp));
    }

    // -------------------------------------------------------------------------
    //  Deactivation & Withdrawal
    // -------------------------------------------------------------------------

    /**
     * @notice Deactivate a registered device. Only the device owner may call this.
     *
     * @dev After deactivation, the device can no longer submit PoAC records.
     *      The deposit is locked for DEACTIVATION_COOLDOWN before withdrawal.
     *
     * @param _deviceId The device to deactivate.
     */
    function deactivateDevice(bytes32 _deviceId) external {
        DeviceInfo storage dev = _devices[_deviceId];
        if (dev.registeredAt == 0) revert DeviceNotFound(_deviceId);
        if (!dev.active) revert DeviceNotActive(_deviceId);
        if (dev.owner != msg.sender) revert NotDeviceOwner(_deviceId, msg.sender);

        dev.active = false;
        dev.deactivatedAt = uint64(block.timestamp);

        emit DeviceDeactivated(_deviceId, msg.sender, uint64(block.timestamp));
    }

    /**
     * @notice Withdraw deposit after deactivation cooldown has elapsed.
     * @param _deviceId The deactivated device whose deposit to withdraw.
     */
    function withdrawDeposit(bytes32 _deviceId) external nonReentrant {
        DeviceInfo storage dev = _devices[_deviceId];
        if (dev.registeredAt == 0) revert DeviceNotFound(_deviceId);
        if (dev.owner != msg.sender) revert NotDeviceOwner(_deviceId, msg.sender);
        if (dev.active) revert DeviceNotActive(_deviceId); // must be deactivated first
        if (dev.deposit == 0) revert DepositAlreadyWithdrawn(_deviceId);

        uint256 availableAt = uint256(dev.deactivatedAt) + DEACTIVATION_COOLDOWN;
        if (block.timestamp < availableAt) {
            revert CooldownNotElapsed(_deviceId, availableAt);
        }

        uint256 amount = dev.deposit;
        dev.deposit = 0;

        (bool success, ) = payable(dev.owner).call{value: amount}("");
        require(success, "DeviceRegistry: ETH transfer failed");

        emit DepositWithdrawn(_deviceId, dev.owner, amount);
    }

    // -------------------------------------------------------------------------
    //  Reputation
    // -------------------------------------------------------------------------

    /**
     * @notice Update a device's reputation counters and recompute the score.
     *
     * @dev Called by authorized updaters (PoACVerifier, BountyMarket) after
     *      verification events. The reputation score is computed as:
     *
     *          base = verifiedPoACCount (capped contribution)
     *          bonus = corroborationCount * 2
     *          penalty = disputeCount * 10
     *          score = clamp((base + bonus - penalty) * MAX_REPUTATION / normalization, 0, MAX_REPUTATION)
     *
     *      This is a simple initial model; governance can upgrade the formula.
     *
     * @param _deviceId            Target device.
     * @param _addVerified         Number of newly verified PoACs to add.
     * @param _addCorroborations   Number of new corroborations to add.
     * @param _addDisputes         Number of new disputes to add.
     */
    function updateReputation(
        bytes32 _deviceId,
        uint32  _addVerified,
        uint32  _addCorroborations,
        uint32  _addDisputes
    )
        external
        onlyReputationUpdater
    {
        DeviceInfo storage dev = _devices[_deviceId];
        if (dev.registeredAt == 0) revert DeviceNotFound(_deviceId);

        uint16 oldScore = dev.reputationScore;

        // Update counters
        dev.verifiedPoACCount  += _addVerified;
        dev.corroborationCount += _addCorroborations;
        dev.disputeCount       += _addDisputes;

        // Recompute reputation score
        dev.reputationScore = _computeReputation(
            dev.verifiedPoACCount,
            dev.corroborationCount,
            dev.disputeCount
        );

        emit ReputationUpdated(
            _deviceId,
            oldScore,
            dev.reputationScore,
            dev.verifiedPoACCount,
            dev.corroborationCount,
            dev.disputeCount
        );
    }

    /**
     * @dev Internal reputation computation.
     *
     *      Formula (simple linear model with diminishing returns on volume):
     *        - verifiedBase  = min(verifiedCount, 10000) (cap raw PoAC contribution)
     *        - corrobBonus   = corroborations * 2
     *        - disputePenalty = disputes * 10
     *        - rawScore = verifiedBase + corrobBonus - disputePenalty
     *        - Normalize into [0, MAX_REPUTATION] using a logistic-style clamp:
     *          score = rawScore * MAX_REPUTATION / (rawScore + 1000)
     *          (Approaches MAX_REPUTATION asymptotically as rawScore grows)
     *        - If rawScore <= 0, score = 0.
     */
    function _computeReputation(
        uint32 _verified,
        uint32 _corroborations,
        uint32 _disputes
    )
        internal
        pure
        returns (uint16)
    {
        // Cap verified contribution to prevent pure volume gaming
        uint256 verifiedBase = _verified > 10000 ? 10000 : uint256(_verified);
        uint256 corrobBonus = uint256(_corroborations) * 2;
        uint256 disputePenalty = uint256(_disputes) * 10;

        // Compute raw score (can underflow, so use signed logic)
        uint256 positive = verifiedBase + corrobBonus;
        if (disputePenalty >= positive) {
            return 0;
        }
        uint256 rawScore = positive - disputePenalty;

        // Logistic normalization: score = rawScore * MAX / (rawScore + K)
        // K = 1000 gives a nice curve where 1000 raw -> 50%, 5000 -> 83%, 10000 -> 91%
        uint256 score = (rawScore * uint256(MAX_REPUTATION)) / (rawScore + 1000);

        return score > MAX_REPUTATION ? MAX_REPUTATION : uint16(score);
    }

    // -------------------------------------------------------------------------
    //  View functions
    // -------------------------------------------------------------------------

    /**
     * @notice Retrieve full device information.
     * @param _deviceId Device identifier (keccak256 of pubkey).
     * @return info The DeviceInfo struct.
     */
    function getDeviceInfo(bytes32 _deviceId)
        external
        view
        returns (DeviceInfo memory info)
    {
        info = _devices[_deviceId];
        if (info.registeredAt == 0) revert DeviceNotFound(_deviceId);
    }

    /**
     * @notice Check whether a device is registered and active.
     * @param _deviceId Device identifier.
     * @return True if the device exists and is active.
     */
    function isDeviceActive(bytes32 _deviceId) external view returns (bool) {
        return _devices[_deviceId].active;
    }

    /**
     * @notice Returns true if the device is eligible to claim bounty rewards.
     * @dev Base implementation: any active device is eligible.
     *      Overridden in TieredDeviceRegistry to enforce tier-specific restrictions
     *      (e.g., Emulated-tier devices cannot claim bounties).
     * @param _deviceId Device identifier.
     */
    function canClaimBounty(bytes32 _deviceId) public virtual view returns (bool) {
        return _devices[_deviceId].active;
    }

    /**
     * @notice Get the public key bytes for a registered device.
     * @param _deviceId Device identifier.
     * @return The uncompressed SEC1 P256 public key (65 bytes).
     */
    function getDevicePubkey(bytes32 _deviceId) external view returns (bytes memory) {
        DeviceInfo storage dev = _devices[_deviceId];
        if (dev.registeredAt == 0) revert DeviceNotFound(_deviceId);
        return dev.pubkey;
    }

    /**
     * @notice Get the reputation score for a device.
     * @param _deviceId Device identifier.
     * @return score Reputation score in [0, MAX_REPUTATION] (basis points).
     */
    function getReputationScore(bytes32 _deviceId) external view returns (uint16 score) {
        DeviceInfo storage dev = _devices[_deviceId];
        if (dev.registeredAt == 0) revert DeviceNotFound(_deviceId);
        return dev.reputationScore;
    }

    /**
     * @notice Derive the deviceId from a public key without registering.
     * @param _pubkey Uncompressed SEC1 P256 public key (65 bytes).
     * @return deviceId keccak256 hash of the public key.
     */
    function computeDeviceId(bytes calldata _pubkey) external pure returns (bytes32) {
        return keccak256(_pubkey);
    }
}

contracts/PoACVerifier.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./DeviceRegistry.sol";

/**
 * @title PoACVerifier
 * @author VAPI Project
 * @notice On-chain verification of Proof of Autonomous Cognition (PoAC) records
 *         submitted by VAPI devices on the IoTeX blockchain.
 *
 * @dev Verification accepts the raw 164-byte body exactly as signed by the
 *      firmware (no re-serialization), plus the 64-byte ECDSA-P256 signature.
 *
 *      Pipeline:
 *        1. Validate body/signature lengths (164 / 64 bytes).
 *        2. Check device is registered and active in {DeviceRegistry}.
 *        3. Compute SHA-256 of the raw body (identical to firmware digest).
 *        4. Verify the ECDSA-P256 signature over that SHA-256 digest
 *           using the IoTeX P256 precompile at address 0x0100.
 *        5. Parse fields from the raw body for semantic validation.
 *        6. Validate monotonic counter, timestamp skew, chain linkage.
 *        7. Store SHA-256(body) as the chain head and record hash.
 *           This matches the firmware's chain_head = SHA-256(serialized_body),
 *           ensuring prev_poac_hash linkage is consistent end-to-end.
 *        8. Update the device's reputation in {DeviceRegistry}.
 *
 *      Raw body layout (big-endian, matching firmware poac_serialize()):
 *        Offset  Field                  Size
 *        0x00    prev_poac_hash         32B
 *        0x20    sensor_commitment      32B
 *        0x40    model_manifest_hash    32B
 *        0x60    world_model_hash       32B
 *        0x80    inference_result       1B
 *        0x81    action_code            1B
 *        0x82    confidence             1B
 *        0x83    battery_pct            1B
 *        0x84    monotonic_ctr          4B   (uint32 big-endian)
 *        0x88    timestamp_ms           8B   (int64 big-endian)
 *        0x90    latitude               8B   (IEEE 754 double big-endian)
 *        0x98    longitude              8B   (IEEE 754 double big-endian)
 *        0xA0    bounty_id              4B   (uint32 big-endian)
 *        ---     total                  164B
 *
 *      ## IoTeX P256 Precompile (0x0100)
 *      Input:  hash(32) || r(32) || s(32) || x(32) || y(32) = 160 bytes
 *      Output: 0x01 (32-byte left-padded) if valid, 0x00 otherwise.
 */
contract PoACVerifier is Ownable, ReentrancyGuard {

    // -------------------------------------------------------------------------
    //  Constants
    // -------------------------------------------------------------------------

    /// @notice IoTeX P256 signature verification precompile address.
    address public constant P256_PRECOMPILE = address(0x0100);

    /// @notice Size of the serialized PoAC body (before signature).
    uint256 public constant POAC_BODY_SIZE = 164;

    /// @notice Size of the ECDSA-P256 signature (r || s).
    uint256 public constant POAC_SIG_SIZE = 64;

    /// @notice Maximum allowable timestamp skew (seconds).
    uint256 public maxTimestampSkew;

    // -------------------------------------------------------------------------
    //  Data structures
    // -------------------------------------------------------------------------

    /// @notice Chain tracking state for each device.
    struct ChainState {
        bytes32 lastRecordHash; // SHA-256 of the most recent verified body
        uint32  lastCounter;    // Last verified monotonic counter value
        uint32  verifiedCount;  // Total verified PoAC records for this device
        bool    initialized;    // True after first verified record
    }

    // -------------------------------------------------------------------------
    //  State
    // -------------------------------------------------------------------------

    /// @notice Reference to the DeviceRegistry contract.
    DeviceRegistry public deviceRegistry;

    /// @notice Per-device chain integrity state. deviceId => ChainState.
    mapping(bytes32 => ChainState) private _chainState;

    /// @notice Record hash => true if this PoAC has been verified on-chain.
    mapping(bytes32 => bool) public verifiedRecords;

    /// @notice Record hash => true if this body was ever submitted to this contract.
    /// @dev    Unlike {verifiedRecords} (set only on full verification success),
    ///         submittedHashes is set in the OUTER batch context so it persists even
    ///         when the child verification call reverts, permanently preventing
    ///         re-submission of any body that entered a batch — regardless of outcome.
    mapping(bytes32 => bool) public submittedHashes;

    /// @notice Total number of PoAC records verified across all devices.
    uint256 public totalVerifiedCount;

    // -------------------------------------------------------------------------
    //  Events
    // -------------------------------------------------------------------------

    /// @notice Emitted when a PoAC record is successfully verified.
    event PoACVerified(
        bytes32 indexed deviceId,
        bytes32 indexed recordHash,
        uint32  monotonicCtr,
        int64   timestampMs,
        uint8   actionCode,
        uint8   inferenceResult,
        uint32  bountyId
    );

    /// @notice Emitted when a batch verification completes.
    event BatchVerified(
        uint256 submitted,
        uint256 verified,
        uint256 rejected
    );

    // -------------------------------------------------------------------------
    //  Errors
    // -------------------------------------------------------------------------

    error DeviceNotRegistered(bytes32 deviceId);
    error DeviceNotActive(bytes32 deviceId);
    error InvalidSignature(bytes32 deviceId, bytes32 recordHash);
    error CounterNotMonotonic(bytes32 deviceId, uint32 submitted, uint32 lastKnown);
    error TimestampOutOfRange(bytes32 deviceId, int64 recordTs, uint256 blockTs, uint256 maxSkew);
    error ChainLinkageBroken(bytes32 deviceId, bytes32 submitted, bytes32 expected);
    error RecordAlreadyVerified(bytes32 recordHash);
    error RecordAlreadySubmitted(bytes32 recordHash);
    error InvalidBodyLength(uint256 provided);
    error InvalidSignatureLength(uint256 provided);
    error EmptyBatch();
    error ArrayLengthMismatch();

    // -------------------------------------------------------------------------
    //  Constructor
    // -------------------------------------------------------------------------

    /**
     * @param _deviceRegistry   Address of the deployed DeviceRegistry contract.
     * @param _maxTimestampSkew  Maximum acceptable timestamp skew in seconds.
     */
    constructor(address _deviceRegistry, uint256 _maxTimestampSkew) Ownable(msg.sender) {
        deviceRegistry = DeviceRegistry(_deviceRegistry);
        maxTimestampSkew = _maxTimestampSkew;
    }

    // -------------------------------------------------------------------------
    //  Admin
    // -------------------------------------------------------------------------

    function setMaxTimestampSkew(uint256 _newSkew) external onlyOwner {
        maxTimestampSkew = _newSkew;
    }

    // -------------------------------------------------------------------------
    //  Core verification — single record
    // -------------------------------------------------------------------------

    /**
     * @notice Verify a single PoAC record from its raw wire-format bytes.
     *
     * @param _deviceId   Device identifier (keccak256 of device pubkey).
     * @param _rawBody    The 164-byte serialized PoAC body (exactly as signed).
     * @param _signature  ECDSA-P256 signature (r || s, 64 bytes).
     * @return recordHash SHA-256 of the body (matches firmware chain head).
     */
    function verifyPoAC(
        bytes32 _deviceId,
        bytes calldata _rawBody,
        bytes calldata _signature
    )
        external
        nonReentrant
        returns (bytes32 recordHash)
    {
        // Early length check enables hash pre-computation for the replay gate.
        if (_rawBody.length != POAC_BODY_SIZE) revert InvalidBodyLength(_rawBody.length);
        bytes32 h = sha256(_rawBody);
        // Anti-replay gate: reject any body previously seen at this address.
        // In the single-TX path, submittedHashes is set inside _verifyInternal
        // only on full success, so a transient failure (bad sig, clock skew) does
        // NOT permanently blacklist the body — the bridge can retry.
        if (submittedHashes[h]) revert RecordAlreadySubmitted(h);
        return _verifyInternal(_deviceId, _rawBody, _signature);
    }

    // -------------------------------------------------------------------------
    //  Batch verification
    // -------------------------------------------------------------------------

    /**
     * @notice Batch-verify multiple PoAC records.
     *
     * @dev Records that fail are silently skipped (not reverted).
     *      The BatchVerified event reports counts.
     */
    function verifyPoACBatch(
        bytes32[] calldata _deviceIds,
        bytes[] calldata _rawBodies,
        bytes[] calldata _signatures
    )
        external
        nonReentrant
        returns (bytes32[] memory recordHashes)
    {
        uint256 count = _deviceIds.length;
        if (count == 0) revert EmptyBatch();
        if (count != _rawBodies.length || count != _signatures.length) {
            revert ArrayLengthMismatch();
        }

        recordHashes = new bytes32[](count);
        uint256 verified = 0;
        uint256 rejected = 0;

        for (uint256 i = 0; i < count; i++) {
            // Pre-compute hash in OUTER context so submittedHashes[h] persists
            // even when the child call reverts (e.g., bad signature, counter mismatch,
            // timestamp out of range).  This permanently prevents re-submission of any
            // body that entered this batch — distinguishing VAPI's batch path from the
            // single-TX retry-allowed path of verifyPoAC().
            if (_rawBodies[i].length != POAC_BODY_SIZE) {
                recordHashes[i] = bytes32(0);
                rejected++;
                continue;
            }
            bytes32 h = sha256(_rawBodies[i]);
            if (submittedHashes[h]) {
                recordHashes[i] = bytes32(0);
                rejected++;
                continue;
            }
            submittedHashes[h] = true;   // Persists in outer TX even on child revert

            try this.verifyPoACExternal(
                _deviceIds[i],
                _rawBodies[i],
                _signatures[i]
            ) returns (bytes32 hash) {
                recordHashes[i] = hash;
                verified++;
            } catch {
                recordHashes[i] = bytes32(0);
                rejected++;
            }
        }

        emit BatchVerified(count, verified, rejected);
    }

    /**
     * @notice External wrapper for try/catch in batch. Not for direct use.
     */
    function verifyPoACExternal(
        bytes32 _deviceId,
        bytes calldata _rawBody,
        bytes calldata _signature
    )
        external
        returns (bytes32)
    {
        require(msg.sender == address(this), "PoACVerifier: internal only");
        return _verifyInternal(_deviceId, _rawBody, _signature);
    }

    // -------------------------------------------------------------------------
    //  Internal verification logic
    // -------------------------------------------------------------------------

    /// @dev Parsed fields from the raw body, packed into a struct to avoid stack-too-deep.
    struct ParsedFields {
        bytes32 prevHash;
        uint8   inferenceResult;
        uint8   actionCode;
        uint32  monotonicCtr;
        int64   timestampMs;
        uint32  bountyId;
    }

    function _verifyInternal(
        bytes32 _deviceId,
        bytes calldata _rawBody,
        bytes calldata _signature
    )
        internal
        returns (bytes32 recordHash)
    {
        // 1. Validate lengths
        if (_rawBody.length != POAC_BODY_SIZE) revert InvalidBodyLength(_rawBody.length);
        if (_signature.length != POAC_SIG_SIZE) revert InvalidSignatureLength(_signature.length);

        // 2. Check device is registered and active
        _requireDeviceActive(_deviceId);

        // 3. Compute SHA-256 of raw body — identical to firmware digest
        recordHash = sha256(_rawBody);

        // 4. Prevent duplicate verification
        if (verifiedRecords[recordHash]) revert RecordAlreadyVerified(recordHash);

        // 5. Verify ECDSA-P256 signature via IoTeX precompile
        _requireValidSignature(_deviceId, recordHash, _signature);

        // 6. Parse fields from raw body
        ParsedFields memory f = _parseBody(_rawBody);

        // 7. Validate monotonic counter
        ChainState storage chain = _chainState[_deviceId];
        if (chain.initialized && f.monotonicCtr <= chain.lastCounter) {
            revert CounterNotMonotonic(_deviceId, f.monotonicCtr, chain.lastCounter);
        }

        // 8. Validate timestamp within acceptable skew
        _validateTimestamp(_deviceId, f.timestampMs);

        // 9. Validate chain linkage (if not genesis record)
        if (f.prevHash != bytes32(0)) {
            if (chain.initialized && f.prevHash != chain.lastRecordHash) {
                revert ChainLinkageBroken(_deviceId, f.prevHash, chain.lastRecordHash);
            }
        }

        // 10. Update chain state
        chain.lastRecordHash = recordHash;
        chain.lastCounter = f.monotonicCtr;
        chain.verifiedCount++;
        chain.initialized = true;

        submittedHashes[recordHash] = true;  // Anti-replay: marks body as seen
        verifiedRecords[recordHash] = true;  // Attestation registry: body fully verified
        totalVerifiedCount++;

        // 11. Update device reputation
        try deviceRegistry.updateReputation(_deviceId, 1, 0, 0) {} catch {}

        // 12. Emit event
        emit PoACVerified(
            _deviceId, recordHash, f.monotonicCtr, f.timestampMs,
            f.actionCode, f.inferenceResult, f.bountyId
        );
    }

    function _requireDeviceActive(bytes32 _deviceId) internal view {
        if (!deviceRegistry.isDeviceActive(_deviceId)) {
            try deviceRegistry.getDeviceInfo(_deviceId) returns (
                DeviceRegistry.DeviceInfo memory
            ) {
                revert DeviceNotActive(_deviceId);
            } catch {
                revert DeviceNotRegistered(_deviceId);
            }
        }
    }

    function _requireValidSignature(
        bytes32 _deviceId, bytes32 _digest, bytes calldata _sig
    ) internal virtual view {
        bytes memory pubkey = deviceRegistry.getDevicePubkey(_deviceId);
        if (!_verifyP256Signature(_digest, _sig, pubkey)) {
            revert InvalidSignature(_deviceId, _digest);
        }
    }

    function _validateTimestamp(bytes32 _deviceId, int64 _timestampMs) internal view {
        uint256 blockTsMs = block.timestamp * 1000;
        uint256 recordTsAbs = _timestampMs >= 0 ? uint256(uint64(_timestampMs)) : 0;
        uint256 skewMs = maxTimestampSkew * 1000;
        if (recordTsAbs > blockTsMs + skewMs || recordTsAbs + skewMs < blockTsMs) {
            revert TimestampOutOfRange(_deviceId, _timestampMs, block.timestamp, maxTimestampSkew);
        }
    }

    function _parseBody(bytes calldata _rawBody)
        internal pure returns (ParsedFields memory f)
    {
        assembly {
            let fPtr := f
            // prevPoACHash: bytes 0-31
            mstore(fPtr, calldataload(_rawBody.offset))

            // Fields at offset 128 (after 4x32B hashes)
            let w := calldataload(add(_rawBody.offset, 128))
            // inferenceResult = byte 0
            mstore(add(fPtr, 0x20), byte(0, w))
            // actionCode = byte 1
            mstore(add(fPtr, 0x40), byte(1, w))
            // monotonicCtr = bytes 4-7
            mstore(add(fPtr, 0x60), and(shr(192, w), 0xFFFFFFFF))
            // timestampMs: bytes 136-143
            mstore(add(fPtr, 0x80), shr(192, calldataload(add(_rawBody.offset, 136))))
            // bountyId: bytes 160-163
            mstore(add(fPtr, 0xA0), shr(224, calldataload(add(_rawBody.offset, 160))))
        }
    }

    // -------------------------------------------------------------------------
    //  P256 Signature Verification
    // -------------------------------------------------------------------------

    /**
     * @dev Verify ECDSA-P256 signature using IoTeX precompile at 0x0100.
     *      Input:  digest(32) || r(32) || s(32) || x(32) || y(32) = 160 bytes
     *      Output: 0x00..01 (32 bytes) if valid, 0x00..00 if invalid.
     */
    function _verifyP256Signature(
        bytes32 _digest,
        bytes calldata _sig,
        bytes memory _pubkey
    )
        internal
        view
        returns (bool)
    {
        require(_sig.length == 64, "PoACVerifier: signature must be 64 bytes");
        require(_pubkey.length == 65, "PoACVerifier: pubkey must be 65 bytes");

        bytes32 r;
        bytes32 s;
        assembly {
            r := calldataload(_sig.offset)
            s := calldataload(add(_sig.offset, 32))
        }

        // Extract x, y from pubkey (skip 0x04 prefix byte)
        bytes32 x;
        bytes32 y;
        assembly {
            x := mload(add(_pubkey, 33))
            y := mload(add(_pubkey, 65))
        }

        bytes memory input = abi.encodePacked(_digest, r, s, x, y);
        (bool success, bytes memory result) = P256_PRECOMPILE.staticcall(input);

        if (!success || result.length < 32) {
            return false;
        }

        uint256 valid;
        assembly {
            valid := mload(add(result, 32))
        }

        return valid == 1;
    }

    // -------------------------------------------------------------------------
    //  View functions
    // -------------------------------------------------------------------------

    function getChainHead(bytes32 _deviceId)
        external
        view
        returns (bytes32 lastRecordHash, uint32 lastCounter, bool initialized)
    {
        ChainState storage chain = _chainState[_deviceId];
        return (chain.lastRecordHash, chain.lastCounter, chain.initialized);
    }

    function getVerifiedCount(bytes32 _deviceId) external view returns (uint32 count) {
        return _chainState[_deviceId].verifiedCount;
    }

    function isRecordVerified(bytes32 _recordHash) external view returns (bool) {
        return verifiedRecords[_recordHash];
    }
}

contracts/ProgressAttestation.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./PoACVerifier.sol";

/**
 * @title ProgressAttestation
 * @author VAPI Project
 * @notice Verifiable progress proofs for autonomous gaming coaching.
 *
 * @dev Stores cryptographic attestations of measurable skill improvement,
 *      backed by verified PoAC records. Coaching platforms can query these
 *      proofs to verify student improvement before issuing certificates,
 *      badges, or processing refund guarantees.
 *
 *      Workflow:
 *        1. Student plays with VAPI device, generating PoAC chain
 *        2. Agent detects improvement (e.g., reaction_time decreased 15%)
 *        3. Coach or student calls attestProgress() with baseline + current records
 *        4. Contract verifies both records exist on-chain
 *        5. Progress attestation stored with metric type and improvement BPS
 *        6. Coaching platform queries getProgressHistory() for verification
 *
 *      Metric types:
 *        REACTION_TIME   — Average reaction time improvement
 *        ACCURACY        — Stick/aim precision improvement
 *        CONSISTENCY     — Reduced timing variance
 *        COMBO_EXECUTION — Complex input sequence mastery
 */
contract ProgressAttestation is Ownable {

    // ─── Enums ──────────────────────────────────────────────────────────

    enum MetricType { REACTION_TIME, ACCURACY, CONSISTENCY, COMBO_EXECUTION }

    // ─── Data Structures ────────────────────────────────────────────────

    struct ProgressRecord {
        bytes32    deviceId;
        bytes32    baselineRecordHash;   // PoAC hash from before coaching
        bytes32    currentRecordHash;    // PoAC hash from after coaching
        MetricType metricType;
        uint32     improvementBps;       // Improvement in basis points (100 = 1%)
        uint64     attestedAt;           // Block timestamp
        address    attestor;             // Who submitted (coach or student)
    }

    // ─── State ──────────────────────────────────────────────────────────

    PoACVerifier public poACVerifier;

    /// @notice Global attestation counter (also serves as attestation ID).
    uint256 public attestationCount;

    /// @notice attestationId => ProgressRecord
    mapping(uint256 => ProgressRecord) private _attestations;

    /// @notice deviceId => array of attestation IDs
    mapping(bytes32 => uint256[]) private _deviceAttestations;

    /// @notice Prevent duplicate attestations for same baseline+current pair
    mapping(bytes32 => bool) private _pairUsed;

    // ─── Events ─────────────────────────────────────────────────────────

    event ProgressAttested(
        bytes32    indexed deviceId,
        uint256    indexed attestationId,
        MetricType metricType,
        uint32     improvementBps,
        address    attestor
    );

    // ─── Errors ─────────────────────────────────────────────────────────

    error BaselineNotVerified(bytes32 recordHash);
    error CurrentNotVerified(bytes32 recordHash);
    error PairAlreadyAttested(bytes32 baselineHash, bytes32 currentHash);
    error ZeroImprovement();
    error SameRecord();

    // ─── Constructor ────────────────────────────────────────────────────

    constructor(address _poACVerifier) Ownable(msg.sender) {
        poACVerifier = PoACVerifier(_poACVerifier);
    }

    // ─── Core Functions ─────────────────────────────────────────────────

    /**
     * @notice Attest to measurable progress between two verified PoAC records.
     *
     * @param _deviceId         Device that generated both records.
     * @param _baselineHash     SHA-256 hash of the baseline (pre-coaching) PoAC body.
     * @param _currentHash      SHA-256 hash of the current (post-coaching) PoAC body.
     * @param _metricType       Which skill metric improved.
     * @param _improvementBps   Improvement magnitude in basis points (100 = 1%).
     * @return attestationId    Unique ID for this attestation.
     */
    function attestProgress(
        bytes32    _deviceId,
        bytes32    _baselineHash,
        bytes32    _currentHash,
        MetricType _metricType,
        uint32     _improvementBps
    ) external returns (uint256 attestationId) {
        // Validations
        if (_baselineHash == _currentHash) revert SameRecord();
        if (_improvementBps == 0) revert ZeroImprovement();

        if (!poACVerifier.isRecordVerified(_baselineHash)) {
            revert BaselineNotVerified(_baselineHash);
        }
        if (!poACVerifier.isRecordVerified(_currentHash)) {
            revert CurrentNotVerified(_currentHash);
        }

        bytes32 pairKey = keccak256(abi.encodePacked(_baselineHash, _currentHash));
        if (_pairUsed[pairKey]) {
            revert PairAlreadyAttested(_baselineHash, _currentHash);
        }
        _pairUsed[pairKey] = true;

        // Store attestation
        attestationId = attestationCount++;
        _attestations[attestationId] = ProgressRecord({
            deviceId: _deviceId,
            baselineRecordHash: _baselineHash,
            currentRecordHash: _currentHash,
            metricType: _metricType,
            improvementBps: _improvementBps,
            attestedAt: uint64(block.timestamp),
            attestor: msg.sender
        });

        _deviceAttestations[_deviceId].push(attestationId);

        emit ProgressAttested(
            _deviceId, attestationId, _metricType, _improvementBps, msg.sender
        );
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function getAttestation(uint256 _id)
        external view returns (ProgressRecord memory)
    {
        return _attestations[_id];
    }

    function getDeviceAttestationCount(bytes32 _deviceId)
        external view returns (uint256)
    {
        return _deviceAttestations[_deviceId].length;
    }

    function getDeviceAttestationIds(bytes32 _deviceId)
        external view returns (uint256[] memory)
    {
        return _deviceAttestations[_deviceId];
    }

    function getProgressHistory(bytes32 _deviceId)
        external view returns (ProgressRecord[] memory)
    {
        uint256[] storage ids = _deviceAttestations[_deviceId];
        ProgressRecord[] memory records = new ProgressRecord[](ids.length);
        for (uint256 i = 0; i < ids.length; i++) {
            records[i] = _attestations[ids[i]];
        }
        return records;
    }
}

contracts/SkillOracle.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./PoACVerifier.sol";
import "./DeviceRegistry.sol";

/**
 * @title SkillOracle
 * @author VAPI Project
 * @notice On-chain skill rating oracle for esports and gaming DAOs.
 *
 * @dev Aggregates verified PoAC records into an ELO-inspired skill rating
 *      per device. Gaming DAOs can query this oracle for:
 *        - Tournament eligibility gating
 *        - Governance weight by proven skill
 *        - Fair reward distribution based on performance
 *
 *      Rating algorithm:
 *        - Base rating starts at 1000 (Bronze)
 *        - NOMINAL gameplay: +5 per verified record
 *        - SKILLED gameplay:  +12 per verified record
 *        - CHEAT detection:   -200 per cheat flag (harsh penalty)
 *        - Confidence scaling: gain *= confidence / 255
 *        - Rating floor: 0, ceiling: 3000
 *
 *      Tier brackets:
 *        Bronze:   0 - 999
 *        Silver:   1000 - 1499
 *        Gold:     1500 - 1999
 *        Platinum: 2000 - 2499
 *        Diamond:  2500 - 3000
 *
 *      Only processes records already verified by {PoACVerifier}.
 */
contract SkillOracle is Ownable {

    // ─── Enums ──────────────────────────────────────────────────────────

    enum SkillTier { Bronze, Silver, Gold, Platinum, Diamond }

    // ─── Data Structures ────────────────────────────────────────────────

    struct SkillProfile {
        uint32  rating;          // ELO-like rating [0, 3000]
        uint32  gamesPlayed;     // Total verified records processed
        uint32  cleanGames;      // Records with no cheat flags
        uint32  cheatFlags;      // Total cheat detections
        uint64  lastUpdated;     // Block timestamp of last update
        bool    initialized;     // True after first record
    }

    // ─── Constants ──────────────────────────────────────────────────────

    uint32 public constant INITIAL_RATING = 1000;
    uint32 public constant MAX_RATING = 3000;
    uint32 public constant NOMINAL_GAIN = 5;
    uint32 public constant SKILLED_GAIN = 12;
    uint32 public constant CHEAT_PENALTY = 200;

    /// @notice Default minimum block interval between rating updates per device.
    /// @dev    At IoTeX's ~5s block time, 1 block ≈ 5 seconds between updates.
    ///         Prevents same-block burst manipulation (submitting all historical
    ///         records in one block to spike rating for tournament eligibility).
    uint256 public constant DEFAULT_MIN_INTERVAL = 1;

    // Inference result code ranges (from firmware)
    uint8 public constant INFER_NOMINAL = 0x20;
    uint8 public constant INFER_SKILLED = 0x21;
    uint8 public constant INFER_CHEAT_MIN = 0x22;
    uint8 public constant INFER_CHEAT_MAX = 0x29;

    // ─── State ──────────────────────────────────────────────────────────

    PoACVerifier public poACVerifier;
    mapping(bytes32 => SkillProfile) private _profiles;
    mapping(bytes32 => bool) public processedRecords;
    uint256 public totalProfileCount;

    // ─── Rate Limiting State ─────────────────────────────────────────────

    /// @notice Minimum blocks between successive rating updates for the same device.
    /// @dev    Owner-adjustable. Set to 0 to disable rate limiting.
    uint256 public minUpdateInterval;

    /// @notice Last block number at which a device received a rating update.
    mapping(bytes32 => uint256) private _lastUpdateBlock;

    // ─── Events ─────────────────────────────────────────────────────────

    event SkillRatingUpdated(
        bytes32 indexed deviceId,
        uint32  oldRating,
        uint32  newRating,
        SkillTier tier,
        uint32  gamesPlayed
    );

    // ─── Errors ─────────────────────────────────────────────────────────

    error RecordNotVerified(bytes32 recordHash);
    error RecordAlreadyProcessed(bytes32 recordHash);
    error RateLimitExceeded(bytes32 deviceId, uint256 currentBlock, uint256 nextAllowedBlock);

    // ─── Constructor ────────────────────────────────────────────────────

    constructor(address _poACVerifier) Ownable(msg.sender) {
        poACVerifier = PoACVerifier(_poACVerifier);
        minUpdateInterval = DEFAULT_MIN_INTERVAL;
    }

    // ─── Core Functions ─────────────────────────────────────────────────

    /**
     * @notice Update a device's skill rating based on a verified PoAC record.
     *
     * @param _deviceId    Device identifier.
     * @param _recordHash  SHA-256 hash of the verified PoAC body.
     * @param _inferenceResult  The inference code from the PoAC record.
     * @param _confidence  The confidence value [0-255] from the PoAC record.
     */
    function updateSkillRating(
        bytes32 _deviceId,
        bytes32 _recordHash,
        uint8   _inferenceResult,
        uint8   _confidence
    ) external {
        // 1. Verify the record exists on-chain
        if (!poACVerifier.isRecordVerified(_recordHash)) {
            revert RecordNotVerified(_recordHash);
        }

        // 2. Prevent double-counting
        if (processedRecords[_recordHash]) {
            revert RecordAlreadyProcessed(_recordHash);
        }

        // 3. Rate limit: enforce minimum block interval between updates per device.
        //    Prevents burst submission of historical records to spike ratings.
        //    Different devices are independent — cross-device updates are not rate-limited.
        uint256 last = _lastUpdateBlock[_deviceId];
        if (last != 0 && block.number < last + minUpdateInterval) {
            revert RateLimitExceeded(_deviceId, block.number, last + minUpdateInterval);
        }

        // State changes (after all checks to avoid partial-write on revert)
        processedRecords[_recordHash] = true;
        _lastUpdateBlock[_deviceId] = block.number;

        // 3. Initialize profile if needed
        SkillProfile storage profile = _profiles[_deviceId];
        if (!profile.initialized) {
            profile.rating = INITIAL_RATING;
            profile.initialized = true;
            totalProfileCount++;
        }

        uint32 oldRating = profile.rating;

        // 4. Compute rating delta
        if (_inferenceResult >= INFER_CHEAT_MIN && _inferenceResult <= INFER_CHEAT_MAX) {
            // Cheat detected — harsh penalty
            profile.cheatFlags++;
            if (profile.rating > CHEAT_PENALTY) {
                profile.rating -= CHEAT_PENALTY;
            } else {
                profile.rating = 0;
            }
        } else if (_inferenceResult == INFER_SKILLED) {
            // Skilled play — larger gain, scaled by confidence
            uint32 gain = (SKILLED_GAIN * uint32(_confidence)) / 255;
            if (gain == 0) gain = 1;
            profile.rating += gain;
            profile.cleanGames++;
        } else {
            // Nominal play — base gain, scaled by confidence
            uint32 gain = (NOMINAL_GAIN * uint32(_confidence)) / 255;
            if (gain == 0) gain = 1;
            profile.rating += gain;
            profile.cleanGames++;
        }

        // 5. Clamp to [0, MAX_RATING]
        if (profile.rating > MAX_RATING) {
            profile.rating = MAX_RATING;
        }

        profile.gamesPlayed++;
        profile.lastUpdated = uint64(block.timestamp);

        // 6. Emit event
        emit SkillRatingUpdated(
            _deviceId, oldRating, profile.rating,
            _getTier(profile.rating), profile.gamesPlayed
        );
    }

    // ─── Admin ──────────────────────────────────────────────────────────

    /**
     * @notice Set the minimum block interval between rating updates for any device.
     * @dev    Set to 0 to disable rate limiting entirely.
     *         At IoTeX's ~5s block time, 12 blocks ≈ 60s minimum between updates.
     */
    function setMinUpdateInterval(uint256 _blocks) external onlyOwner {
        minUpdateInterval = _blocks;
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function getSkillRating(bytes32 _deviceId)
        external view returns (uint32 rating, uint32 gamesPlayed, uint64 lastUpdated)
    {
        SkillProfile storage p = _profiles[_deviceId];
        return (p.rating, p.gamesPlayed, p.lastUpdated);
    }

    function getSkillProfile(bytes32 _deviceId)
        external view returns (SkillProfile memory)
    {
        return _profiles[_deviceId];
    }

    function getSkillTier(bytes32 _deviceId)
        external view returns (SkillTier)
    {
        return _getTier(_profiles[_deviceId].rating);
    }

    // ─── Internal ───────────────────────────────────────────────────────

    function _getTier(uint32 _rating) internal pure returns (SkillTier) {
        if (_rating >= 2500) return SkillTier.Diamond;
        if (_rating >= 2000) return SkillTier.Platinum;
        if (_rating >= 1500) return SkillTier.Gold;
        if (_rating >= 1000) return SkillTier.Silver;
        return SkillTier.Bronze;
    }
}

contracts/TeamProofAggregator.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "./PoACVerifier.sol";

/**
 * @title TeamProofAggregator
 * @author VAPI Project
 * @notice Swarm-based collaborative gaming with verifiable team proofs.
 *
 * @dev Aggregates individual PoAC record hashes from team members into a
 *      compact Merkle root that serves as a team-level attestation.
 *
 *      Use cases:
 *        - Esports tournament integrity: all team members verified clean
 *        - Cooperative game achievements: verifiable team contribution
 *        - DAO governance: team-weighted voting based on collective proof
 *
 *      Merkle construction:
 *        1. Sort individual record hashes lexicographically
 *        2. Compute pairwise keccak256 hashes up the tree
 *        3. Odd leaf is promoted unchanged
 *        4. Root = team attestation hash
 *
 *      Integrity guarantees:
 *        - Every member's record must be verified in PoACVerifier
 *        - No member can have cheat flags (inference in [0x22, 0x29])
 *        - All members must belong to the registered team
 */
contract TeamProofAggregator is Ownable {

    // ─── Constants ──────────────────────────────────────────────────────

    uint8 public constant MIN_TEAM_SIZE = 2;
    uint8 public constant MAX_TEAM_SIZE = 6;

    // ─── Data Structures ────────────────────────────────────────────────

    struct Team {
        bytes32[]  memberDeviceIds;
        address    captain;       // Team creator
        uint64     createdAt;
        bool       active;
    }

    struct TeamProof {
        bytes32    teamId;
        bytes32    merkleRoot;     // Merkle root of sorted record hashes
        bytes32[]  recordHashes;   // Individual PoAC record hashes
        uint8      memberCount;
        bool       allClean;       // True if no cheat flags in any record
        uint64     submittedAt;
        address    submitter;
    }

    // ─── State ──────────────────────────────────────────────────────────

    PoACVerifier public poACVerifier;

    mapping(bytes32 => Team) private _teams;
    mapping(bytes32 => bool) public teamExists;

    /// @notice Global proof counter (also serves as proof ID).
    uint256 public proofCount;

    /// @notice proofId => TeamProof
    mapping(uint256 => TeamProof) private _proofs;

    /// @notice teamId => array of proof IDs
    mapping(bytes32 => uint256[]) private _teamProofs;

    // ─── Events ─────────────────────────────────────────────────────────

    event TeamCreated(
        bytes32 indexed teamId,
        address indexed captain,
        uint8   memberCount
    );

    event TeamProofSubmitted(
        bytes32 indexed teamId,
        uint256 indexed proofId,
        bytes32 merkleRoot,
        uint8   memberCount,
        bool    allClean
    );

    // ─── Errors ─────────────────────────────────────────────────────────

    error TeamAlreadyExists(bytes32 teamId);
    error TeamNotFound(bytes32 teamId);
    error TeamNotActive(bytes32 teamId);
    error InvalidTeamSize(uint256 size);
    error MemberCountMismatch(uint256 expected, uint256 provided);
    error RecordNotVerified(bytes32 recordHash);
    error InvalidMerkleRoot(bytes32 computed, bytes32 submitted);

    // ─── Constructor ────────────────────────────────────────────────────

    constructor(address _poACVerifier) Ownable(msg.sender) {
        poACVerifier = PoACVerifier(_poACVerifier);
    }

    // ─── Team Management ────────────────────────────────────────────────

    /**
     * @notice Register a new team with its member device IDs.
     *
     * @param _teamId     Unique team identifier (e.g., keccak256 of team name).
     * @param _deviceIds  Array of member device IDs (2-6 members).
     */
    function createTeam(
        bytes32 _teamId,
        bytes32[] calldata _deviceIds
    ) external {
        if (teamExists[_teamId]) revert TeamAlreadyExists(_teamId);
        if (_deviceIds.length < MIN_TEAM_SIZE || _deviceIds.length > MAX_TEAM_SIZE) {
            revert InvalidTeamSize(_deviceIds.length);
        }

        Team storage team = _teams[_teamId];
        team.captain = msg.sender;
        team.createdAt = uint64(block.timestamp);
        team.active = true;
        for (uint256 i = 0; i < _deviceIds.length; i++) {
            team.memberDeviceIds.push(_deviceIds[i]);
        }

        teamExists[_teamId] = true;

        emit TeamCreated(_teamId, msg.sender, uint8(_deviceIds.length));
    }

    // ─── Team Proof Submission ──────────────────────────────────────────

    /**
     * @notice Submit a team proof aggregating individual PoAC records.
     *
     * @param _teamId        Team identifier.
     * @param _recordHashes  One verified PoAC record hash per team member (in member order).
     * @param _merkleRoot    Pre-computed Merkle root of sorted record hashes.
     * @return proofId       Unique proof identifier.
     */
    function submitTeamProof(
        bytes32   _teamId,
        bytes32[] calldata _recordHashes,
        bytes32   _merkleRoot
    ) external returns (uint256 proofId) {
        if (!teamExists[_teamId]) revert TeamNotFound(_teamId);

        Team storage team = _teams[_teamId];
        if (!team.active) revert TeamNotActive(_teamId);
        if (_recordHashes.length != team.memberDeviceIds.length) {
            revert MemberCountMismatch(team.memberDeviceIds.length, _recordHashes.length);
        }

        // Verify all records exist on-chain
        bool allClean = true;
        for (uint256 i = 0; i < _recordHashes.length; i++) {
            if (!poACVerifier.isRecordVerified(_recordHashes[i])) {
                revert RecordNotVerified(_recordHashes[i]);
            }
        }

        // Compute and verify Merkle root
        bytes32 computedRoot = _computeMerkleRoot(_recordHashes);
        if (computedRoot != _merkleRoot) {
            revert InvalidMerkleRoot(computedRoot, _merkleRoot);
        }

        // Store proof
        proofId = proofCount++;
        TeamProof storage proof = _proofs[proofId];
        proof.teamId = _teamId;
        proof.merkleRoot = _merkleRoot;
        proof.memberCount = uint8(_recordHashes.length);
        proof.allClean = allClean;
        proof.submittedAt = uint64(block.timestamp);
        proof.submitter = msg.sender;
        for (uint256 i = 0; i < _recordHashes.length; i++) {
            proof.recordHashes.push(_recordHashes[i]);
        }

        _teamProofs[_teamId].push(proofId);

        emit TeamProofSubmitted(
            _teamId, proofId, _merkleRoot,
            uint8(_recordHashes.length), allClean
        );
    }

    // ─── Merkle Tree ────────────────────────────────────────────────────

    /**
     * @dev Compute Merkle root from an array of leaf hashes.
     *      Sorts leaves lexicographically, then hashes pairwise.
     */
    function _computeMerkleRoot(bytes32[] calldata _leaves)
        internal pure returns (bytes32)
    {
        uint256 n = _leaves.length;
        if (n == 1) return _leaves[0];

        // Copy and sort leaves
        bytes32[] memory sorted = new bytes32[](n);
        for (uint256 i = 0; i < n; i++) {
            sorted[i] = _leaves[i];
        }
        _sortBytes32(sorted);

        // Build tree bottom-up
        while (n > 1) {
            uint256 newN = (n + 1) / 2;
            for (uint256 i = 0; i < newN; i++) {
                uint256 left = i * 2;
                uint256 right = left + 1;
                if (right < n) {
                    sorted[i] = keccak256(abi.encodePacked(sorted[left], sorted[right]));
                } else {
                    sorted[i] = sorted[left]; // Promote odd leaf
                }
            }
            n = newN;
        }

        return sorted[0];
    }

    /**
     * @dev Insertion sort for small arrays (max 6 elements).
     */
    function _sortBytes32(bytes32[] memory arr) internal pure {
        for (uint256 i = 1; i < arr.length; i++) {
            bytes32 key = arr[i];
            uint256 j = i;
            while (j > 0 && arr[j - 1] > key) {
                arr[j] = arr[j - 1];
                j--;
            }
            arr[j] = key;
        }
    }

    // ─── View Functions ─────────────────────────────────────────────────

    function getTeam(bytes32 _teamId)
        external view returns (
            bytes32[] memory memberDeviceIds,
            address captain,
            uint64 createdAt,
            bool active
        )
    {
        Team storage team = _teams[_teamId];
        return (team.memberDeviceIds, team.captain, team.createdAt, team.active);
    }

    function getTeamProof(uint256 _proofId)
        external view returns (TeamProof memory)
    {
        return _proofs[_proofId];
    }

    function getTeamProofCount(bytes32 _teamId)
        external view returns (uint256)
    {
        return _teamProofs[_teamId].length;
    }

    function getTeamProofIds(bytes32 _teamId)
        external view returns (uint256[] memory)
    {
        return _teamProofs[_teamId];
    }

    /**
     * @notice Verify a Merkle root against individual record hashes (off-chain helper).
     */
    function computeMerkleRoot(bytes32[] calldata _leaves)
        external pure returns (bytes32)
    {
        return _computeMerkleRoot(_leaves);
    }
}

